<?php namespace App\Http\Middleware; use Closure; use Illuminate\Http\Request; use Illuminate\Support\Facades\RateLimiter; use App\Traits\ApiResponseTrait; class ApiThrottleMiddleware { use ApiResponseTrait; public function handle(Request $request, Closure $next) { $user = $request->user(); $key = 'throttle_api_' . ($user ? $user->id : $request->ip()); $limit = $this->resolveLimit($user); $executed = RateLimiter::attempt($key, $perMinute = $limit, function() {}); if (!$executed) { return $this->errorResponse('تم تجاوز الحد المسموح به من الطلبات. يرجى المحاولة لاحقاً.', 429); } return $next($request); } protected function resolveLimit($user): int { if (!$user) return 60; if ($user->hasRole('admin')) return 500; if ($user->hasRole('manager')) return 200; return 60; } }